async function f(o,a){self.postMessage({type:"progress",progress:20});const{x:p,y:c,width:e,height:h}=a,l=new Blob([o]),s=await createImageBitmap(l);self.postMessage({type:"progress",progress:50});const g=Math.max(0,Math.min(p,s.width)),n=Math.max(0,Math.min(c,s.height)),t=Math.min(e,s.width-g),r=Math.min(h,s.height-n);if(t<=0||r<=0)throw new Error("Invalid crop area");self.postMessage({type:"progress",progress:70});const i=new OffscreenCanvas(t,r);i.getContext("2d").drawImage(s,g,n,t,r,0,0,t,r),self.postMessage({type:"progress",progress:90});const m=await i.convertToBlob({type:"image/png",quality:1});return self.postMessage({type:"progress",progress:100}),m}self.addEventListener("message",async o=>{const{type:a,imageBuffer:p,cropArea:c}=o.data;if(a==="crop")try{self.postMessage({type:"progress",progress:10});const e=await f(p,c);self.postMessage({type:"success",data:{blob:e}})}catch(e){console.error("Crop error:",e),self.postMessage({type:"error",error:e.message||"Failed to crop image"})}});
